const express = require('express');
const axios = require('axios');

const app = express();
const port = 3000;

app.use(express.json());

app.post('/verify-license', async (req, res) => {
  const { license_number } = req.body;

  if (!license_number) {
    return res.status(400).json({ error: 'license_number is required' });
  }

  const PREMBLY_APP_ID = process.env.PREMBLY_APP_ID;
  const PREMBLY_API_KEY = process.env.PREMBLY_API_KEY;

  if (!PREMBLY_APP_ID || !PREMBLY_API_KEY) {
    return res.status(500).json({ error: 'Prembly configuration is missing' });
  }

  try {
    const response = await axios.post(
      'https://api.prembly.com/verification/drivers_license',
      { number: license_number },
      {
        headers: {
          'app-id': PREMBLY_APP_ID,
          'x-api-key': PREMBLY_API_KEY,
        },
      }
    );

    res.json(response.data);
  } catch (error) {
    const statusCode = error.response ? error.response.status : 500;
    const errorData = error.response ? error.response.data : { message: error.message };
    res.status(statusCode).json(errorData);
  }
});

app.listen(port, () => {
  console.log(`Server running on port ${port}`);
});

